/**
 * Story Predictions Artifact Schema
 *
 * Defines the structure for story risk predictions generated by WKFL-007.
 * Includes split_risk, review_cycles, token_estimate, and similar_stories.
 */

import { z } from 'zod'

// ============================================================================
// Supporting Schemas
// ============================================================================

export const SimilarStorySchema = z.object({
  id: z.string(),
  similarity: z.number().min(0).max(1),
  actual_tokens: z.number().int().nullable(),
  actual_cycles: z.number().int().nullable(),
})

export type SimilarStory = z.infer<typeof SimilarStorySchema>

export const ConfidenceLevelSchema = z.enum(['high', 'medium', 'low', 'none'])
export type ConfidenceLevel = z.infer<typeof ConfidenceLevelSchema>

export const StoryPredictionsSchema = z.object({
  split_risk: z.number().min(0).max(1),
  review_cycles: z.number().min(0),
  token_estimate: z.number().int().min(1000),
  confidence: ConfidenceLevelSchema,
  similar_stories: z.array(SimilarStorySchema).max(5),
  model_version: z.literal('1.0.0'),
})

export type StoryPredictions = z.infer<typeof StoryPredictionsSchema>

// ============================================================================
// Heuristic Functions
// ============================================================================

export interface PredictionInput {
  ac_count: number
  title: string
  scope_keywords: string[]
  similar_stories: SimilarStory[]
}

export function calculateSplitRisk(input: PredictionInput): number {
  let split_risk = 0.1

  if (input.ac_count > 5) split_risk += 0.2
  if (input.ac_count > 8) split_risk += 0.3

  const hasBackend = input.scope_keywords.includes('backend')
  const hasFrontend = input.scope_keywords.includes('frontend')
  if (hasBackend && hasFrontend) split_risk += 0.2

  if (input.title.toLowerCase().includes('refactor')) split_risk += 0.15

  return Math.min(1.0, Math.max(0.0, split_risk))
}

export function calculateReviewCycles(input: PredictionInput): number {
  let review_cycles = 1.5

  if (input.scope_keywords.includes('security')) review_cycles += 0.3

  const stories_with_cycles = input.similar_stories.filter(s => s.actual_cycles != null)
  if (stories_with_cycles.length > 0) {
    const similar_avg =
      stories_with_cycles.reduce((sum, s) => sum + (s.actual_cycles ?? 0), 0) /
      stories_with_cycles.length
    review_cycles = review_cycles * 0.6 + similar_avg * 0.4
  }

  return review_cycles
}

export function calculateTokenEstimate(input: PredictionInput): number {
  const stories_with_tokens = input.similar_stories.filter(s => s.actual_tokens != null)

  if (stories_with_tokens.length > 0) {
    const avg_tokens =
      stories_with_tokens.reduce((sum, s) => sum + (s.actual_tokens ?? 0), 0) /
      stories_with_tokens.length
    return Math.round(avg_tokens * 1.1)
  }

  return 150000
}

export function calculateConfidence(similar_stories_count: number): ConfidenceLevel {
  if (similar_stories_count >= 5) return 'high'
  if (similar_stories_count >= 2) return 'medium'
  if (similar_stories_count === 1) return 'low'
  return 'none'
}

export function generatePredictions(input: PredictionInput): StoryPredictions {
  const similar_stories = input.similar_stories.slice(0, 5)

  return {
    split_risk: calculateSplitRisk(input),
    review_cycles: calculateReviewCycles(input),
    token_estimate: calculateTokenEstimate(input),
    confidence: calculateConfidence(similar_stories.length),
    similar_stories,
    model_version: '1.0.0',
  }
}
